import API from './api';

// Поиск объявлений с фильтрами
export const searchListings = async (filters, page = 1) => {
  const params = new URLSearchParams({
    page,
    page_size: 20,
    ...(filters.city && { city: filters.city }),
    ...(filters.dealType && { deal_type: filters.dealType }),
    ...(filters.propertyType && { property_type: filters.propertyType }),
    ...(filters.rooms && { rooms: filters.rooms }),
    ...(filters.minPrice && { min_price: filters.minPrice }),
    ...(filters.maxPrice && { max_price: filters.maxPrice }),
    ...(filters.minArea && { min_area: filters.minArea }),
    ...(filters.maxArea && { max_area: filters.maxArea }),
    ...(filters.metro && { metro: filters.metro }),
    ...(filters.sortBy && { sort_by: filters.sortBy })
  });

  const response = await API.get(`/listings/?${params}`);
  return response.data;
};

// Получить одно объявление
export const getListing = async (id) => {
  const response = await API.get(`/listings/${id}`);
  return response.data;
};

// Получить фото объявления
export const getListingPhotos = async (id) => {
  const response = await API.get(`/listings/${id}/photos`);
  return response.data;
};

// Получить контакты продавца
export const getContacts = async (id) => {
  const response = await API.get(`/listings/${id}/contacts`);
  return response.data;
};

// Похожие объявления
export const getSimilarListings = async (id, limit = 5) => {
  const response = await API.get(`/listings/similar/${id}?limit=${limit}`);
  return response.data;
};

// Зарегистрировать просмотр
export const registerView = async (listingId, userId = null) => {
  await API.post(`/listings/${listingId}/view`, { user_id: userId });
};
